def _detect_best_mode(shape_name: str) -> PipelineMode:
    tokens = _tokenize(shape_name)
    scores = {PipelineMode.SKETCH: 0, PipelineMode.LOGO: 0, PipelineMode.AUTO: 0}

    for keyword_set, mode, score in _MODE_SCORES:
