def _build_attempt_chain(primary: PipelineMode) -> List[PipelineMode]:
    seen: Set[PipelineMode] = {primary}
    chain = [primary]
    for fb in FALLBACK_MAP.get(primary, []):
        if fb not in seen:
            chain.append(fb)
            seen.add(fb)
    return chain

