def _fix_json_control_chars(s: str) -> str:
    """
    Escape literal control characters (newlines, carriage-returns, tabs)
    that appear *inside* JSON string values.  phi3 (and other small LLMs)
    often emit raw newlines in multi-line content fields, which makes the
    string invalid JSON even though the overall structure is correct.
    """
    result = []
    in_string = False
    escape_next = False

    for ch in s:
        if escape_next:
            result.append(ch)
            escape_next = False
            continue

        if ch == "\\" and in_string:
            result.append(ch)
            escape_next = True
            continue

        if ch == '"':
            in_string = not in_string
            result.append(ch)
            continue

        if in_string:
            if ch == "\n":
                result.append("\\n")
            elif ch == "\r":
                result.append("\\r")
            elif ch == "\t":
                result.append("\\t")
            else:
                result.append(ch)
        else:
            result.append(ch)

    return "".join(result)

