                if not _IS_WINDOWS:
                    return _windows_only_msg("screen_click_text")

                fl = self._get_feedback_loop()
                if not fl:
                    return "❌ OCR/FeedbackLoop not available. Install pytesseract to use screen clicking."

                location = fl.find_text_on_screen(target)
