class Sidebar(QWidget):
    nav_clicked = pyqtSignal(str)

    def __init__(self):
        super().__init__()
        self.setMinimumWidth(130)
        self.setMaximumWidth(190)
        self.setStyleSheet(f"""
            QWidget {{
                background-color: {_SIDEBAR_BG};
                border-bottom-left-radius: 12px;
            }}
        """)
        self.buttons = {}
        self._build_ui()
        self.set_active_tab("Chat")

    def _build_ui(self):
        layout = QVBoxLayout(self)
        layout.setContentsMargins(12, 18, 12, 18)
        layout.setSpacing(4)

        # Logo / branding
        logo = QLabel("🤖 BotBro")
        logo.setStyleSheet(f"""
            color: {_ACCENT};
            font-size: 15px;
            font-weight: 700;
            font-family: "Segoe UI", sans-serif;
            letter-spacing: 0.5px;
            padding-bottom: 10px;
        """)
        layout.addWidget(logo)

        # Thin separator
        sep = QFrame()
        sep.setFrameShape(QFrame.HLine)
        sep.setStyleSheet(f"color: #1a1a2a; background: #1a1a2a; max-height: 1px;")
        layout.addWidget(sep)
        layout.addSpacing(8)

        # Nav buttons
        nav_items = [
            ("💬", "Chat"),
            ("📊", "Dashboard"),
            ("🧠", "Memory"),
            ("🌐", "Browser"),
            ("🔴", "Workflows"),
            ("🤖", "Agents"),
            ("🔌", "Plugins"),
            ("⚙️", "Settings"),
        ]

        for icon, label in nav_items:
            btn = QPushButton(f"  {icon}  {label}")
            btn.setCursor(Qt.PointingHandCursor)

            # Connect button click
            btn.clicked.connect(lambda checked, l=label: self._on_nav_click(l))

            layout.addWidget(btn)
            self.buttons[label] = btn

        layout.addStretch()

        # Feature tags
        features = ["OCR Vision", "RAG Memory", "Browser AI", "Multi-Agent"]
        for feat in features:
            tag = QLabel(f"  ✦ {feat}")
            tag.setStyleSheet(f"""
                color: #2a4a6a;
                font-size: 10px;
                font-family: 'Segoe UI', sans-serif;
                padding: 1px 4px;
            """)
            layout.addWidget(tag)

        layout.addSpacing(4)

        # Divider
        sep2 = QFrame()
        sep2.setFrameShape(QFrame.HLine)
        sep2.setStyleSheet("background: #1a1a2a; max-height: 1px;")
        layout.addWidget(sep2)
        layout.addSpacing(6)

        # Version tag
        ver = QLabel("v2.1.0")
        ver.setStyleSheet(f"color: {_TEXT_DIM}; font-size: 10px; font-family: 'Segoe UI';")
        layout.addWidget(ver)

    def _on_nav_click(self, label: str):
        self.set_active_tab(label)
        self.nav_clicked.emit(label)

    def set_active_tab(self, label: str):
        """Update button styles to highlight the active tab."""
        for name, btn in self.buttons.items():
            if name == label:
                btn.setStyleSheet(f"""
                    QPushButton {{
                        background-color: {_ITEM_HOVER};
                        color: {_ACCENT};
                        text-align: left;
                        padding: 9px 10px;
                        border-radius: 8px;
                        font-size: 13px;
                        font-family: "Segoe UI", sans-serif;
                        border: none;
                        font-weight: bold;
                    }}
                """)
            else:
                btn.setStyleSheet(f"""
                    QPushButton {{
                        background-color: transparent;
                        color: {_TEXT_NORMAL};
                        text-align: left;
                        padding: 9px 10px;
                        border-radius: 8px;
                        font-size: 13px;
                        font-family: "Segoe UI", sans-serif;
                        border: none;
                    }}
                    QPushButton:hover {{
                        background-color: {_ITEM_HOVER};
                        color: {_TEXT_BRIGHT};
                    }}
                    QPushButton:pressed {{
                        background-color: #1a1a38;
                    }}
                """)

