class AIService:
    @staticmethod
    def _generate_workspace_tree(start_dir: str, max_depth: int = 3) -> str:
        """Generate a clean visual tree of the workspace directories, excluding IGNORED_DIRS."""
        lines = []
        def _walk(current_dir: str, prefix: str, depth: int):
            if depth > max_depth:
                return
            try:
                items = sorted(os.listdir(current_dir))
            except Exception:
                return

            filtered = []
            for item in items:
                if item in IGNORED_DIRS:
                    continue
                filtered.append(item)

            for i, item in enumerate(filtered):
                path = os.path.join(current_dir, item)
                is_last = (i == len(filtered) - 1)
                connector = "└── " if is_last else "├── "
                lines.append(f"{prefix}{connector}{item}")

                if os.path.isdir(path):
                    new_prefix = prefix + ("    " if is_last else "│   ")
                    _walk(path, new_prefix, depth + 1)

        lines.append(os.path.basename(start_dir) + "/")
        _walk(start_dir, "", 1)
        return "\n".join(lines)

    @staticmethod
    def _read_and_truncate_file(file_path: str, max_size_bytes: int = 30 * 1024) -> str:
        """Read a file. If it exceeds max_size_bytes, returns first 400 lines and last 150 lines."""
        try:
            size = os.path.getsize(file_path)
            with open(file_path, "r", encoding="utf-8", errors="ignore") as f:
                lines = f.readlines()

            if size <= max_size_bytes:
                return "".join(lines)

            # File is too large, apply truncation strategy
            head = lines[:400]
            tail = lines[-150:]
            middle_marker = f"\n... [TRUNCATED {len(lines) - 550} LINES FOR CONTEXT EFFICIENCY] ...\n\n"
            return "".join(head) + middle_marker + "".join(tail)
        except Exception as e:
            return f"[ERROR READING FILE: {e}]"

    def __init__(self, cache_manager=None):
        self.memory = MemoryManager()

        if cache_manager is None:
            import os
            from core.code_intelligence.cache_manager import CacheManager
            workspace_dir = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
            self.cache_manager = CacheManager(workspace_dir)
            self.cache_manager.load_or_rebuild_index()
        else:
            self.cache_manager = cache_manager

        # Phase 3: RAG Memory — initialise VectorMemory and PreferenceLearner
        # Both are optional; if dependencies are missing the service degrades
        # gracefully and skips memory context injection.
        try:
            from core.vector_memory import VectorMemory
            from core.preference_learner import PreferenceLearner
            self.vector_memory     = VectorMemory()
            self.preference_learner = PreferenceLearner(self.vector_memory, DB_PATH)
            self._memory_available  = True
            logger.info("Vector memory initialised (FAISS RAG active).")
        except Exception as e:
            logger.warning(f"Vector memory unavailable: {e}")
            self.vector_memory      = None
            self.preference_learner = None
            self._memory_available  = False

        json_log(logger, "ai_service", status="configured_ollama_only")

    async def process_intent(self, user_text: str) -> Dict[str, Any]:
        """Send input to Ollama, get JSON string, parse it into an intent."""

        # ── Fast path: local image drop from the GUI ─────────────────────────
        # The GUI emits a synthetic "__draw_local__:<path>" sentinel so we can
        # bypass Ollama and route directly to the draw_local_image executor.
        if user_text.startswith("__draw_local__:"):
            image_path = user_text[len("__draw_local__:"):]
            logger.info(f"Local image drop detected: {image_path}")
            return {"intent": "draw_local_image", "image_path": image_path, "target": image_path, "confidence": 1.0}

        # Fix common typos
        user_text = user_text.lower().replace("esay", "essay")

        self.memory.add_message("user", user_text)

        loop = asyncio.get_running_loop()

        def _naive_fallback(text: str) -> Dict[str, Any]:
            text_lower = text.lower().strip()
            if text_lower.startswith("open "):
                return {"intent": "open_app", "target": text_lower[5:].strip(), "confidence": 0.5}
            elif text_lower.startswith("close "):
                return {"intent": "close_app", "target": text_lower[6:].strip(), "confidence": 0.5}
            elif text_lower.startswith("search "):
                return {"intent": "web_search", "target": text_lower[7:].strip(), "confidence": 0.5}
            elif text_lower.startswith("read file "):
                return {"intent": "read_file", "target": text_lower[10:].strip(), "confidence": 0.5}
            elif text_lower.startswith("delete file "):
                return {"intent": "delete_file", "target": text_lower[12:].strip(), "confidence": 0.5}
            elif text_lower.startswith("list directory ") or text_lower.startswith("list dir "):
                target = text_lower.replace("list directory", "").replace("list dir", "").strip()
                return {"intent": "list_directory", "target": target, "confidence": 0.5}
            elif text_lower.startswith("modify file "):
                return {"intent": "modify_file", "target": text_lower[12:].strip(), "content": "Updated content.", "confidence": 0.5}
            elif text_lower.startswith("run command ") or text_lower.startswith("execute command "):
                cmd = text_lower[12:].strip() if text_lower.startswith("run command ") else text_lower[16:].strip()
                return {"intent": "execute_command", "target": cmd, "confidence": 0.5}
            elif any(kw in text_lower for kw in ("what is this error", "explain this error", "help with this error", "why is this failing", "what is on my screen", "read my screen", "explain my screen", "describe my screen")):
                return {"intent": "screen_info", "target": "screen", "content": text, "confidence": 0.6}

            # Local create_file detection (higher priority than write_text)
            local_cf = _detect_create_file_intent_locally(text)
            if local_cf:
                return local_cf
            # Local write_text detection
            local = _detect_write_intent_locally(text)
            if local:
                return local
            # Local draw detection (explicit + implicit)
            local_draw = _detect_draw_intent_locally(text)
            if local_draw:
                return local_draw
            return {"intent": "error", "message": "I couldn't understand that. Could you rephrase? 🤔"}


        try:
            logger.info("Using Ollama")

            # PII Tokenization Phase
            engine = PIIEngine()
            safe_text, pii_context = engine.tokenize(user_text)

            # ── Phase 3: Memory context injection ────────────────────────────
            # Recall semantically similar past interactions and the user's
            # behavioural profile to give Ollama richer context.
            memory_context = ""
            if self._memory_available and self.vector_memory:
                try:
                    recalled = self.vector_memory.recall(user_text, top_k=3)
                    if recalled:
                        memory_context = self.vector_memory.format_for_prompt(recalled)
                    profile = self.preference_learner.get_user_profile_summary()
                    if profile:
                        memory_context = profile + "\n" + memory_context
                except Exception as e:
                    logger.debug(f"Memory recall failed: {e}")


            # ── Project Workspace File Context Injection ─────────────────────
            # Look for mentioned filenames in the user's text (e.g. "main.py")
            # and inject their contents into the context.
            workspace_dir = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
            file_mentions = re.findall(
                r"\b([\w\-]+\.(?:py|txt|js|ts|html|css|java|cpp|c|json|csv|md|jsonl|yml|yaml))\b",
                user_text,
                re.IGNORECASE
            )

            coding_context = ""
            if file_mentions:
                # Add workspace tree first
                tree_str = AIService._generate_workspace_tree(workspace_dir)
                coding_context += f"\n\n[WORKSPACE STRUCTURE]\n{tree_str}\n"

                for fname in set(file_mentions):
                    # Search workspace for this file name
                    matching_paths = []
                    for root, dirs, files in os.walk(workspace_dir):
                        # Filter dirs in-place to avoid walking ignored folders
                        dirs[:] = [d for d in dirs if d not in IGNORED_DIRS]
                        if fname in files:
                            matching_paths.append(os.path.join(root, fname))

                    if len(matching_paths) > 1:
                        rel_paths = ", ".join([os.path.relpath(p, workspace_dir) for p in matching_paths])
                        coding_context += f"\n\n[AMBIGUITY WARNING: Multiple files in the workspace match the name '{fname}': {rel_paths}. Please ask the user to clarify which one they mean instead of guessing.]\n"
                        logger.warning(f"Ambiguity detected for referenced file '{fname}': {rel_paths}")
                    elif len(matching_paths) == 1:
                        found_path = matching_paths[0]
                        rel_path = os.path.relpath(found_path, workspace_dir).replace("\\", "/")
                        code = AIService._read_and_truncate_file(found_path)
                        coding_context += f"\n\n[FILE: {rel_path}]\n```\n{code}\n```"

                        # Inject summaries of its dependencies
                        if hasattr(self, "cache_manager") and getattr(self.cache_manager, "dependency_graph", None):
                            forward_deps = self.cache_manager.dependency_graph.get("forward", {})
                            deps = forward_deps.get(rel_path, [])
                            if deps:
                                coding_context += f"\n\n[DEPENDENCY SUMMARIES FOR {rel_path}]"
                                for dep in deps:
                                    summary_info = self.cache_manager.file_summaries.get(dep, {})
                                    summary_text = summary_info.get("summary", "No summary available.")
                                    coding_context += f"\n- `{dep}`: {summary_text}"

                        logger.info(f"Injected codebase context for referenced file: {rel_path}")

            if coding_context:
                memory_context = (memory_context + "\n" + coding_context).strip()

            # Use context-aware Ollama call when memory context is available
            if memory_context:
                ollama_raw = await loop.run_in_executor(
                    None, call_ollama_with_context, safe_text, memory_context
                )
            else:
                ollama_raw = await loop.run_in_executor(None, call_ollama, safe_text)

            if ollama_raw:
                # PII Restoration Phase
                if pii_context.has_pii():
                    ollama_raw = engine.restore(ollama_raw, pii_context)

                self.memory.add_message("assistant", ollama_raw)
                parsed = CommandParser.parse(ollama_raw)

                if parsed.get("intent") in ("open_app", "write_text") and _FILE_VERBS.search(user_text):
                    logger.warning(
                        "Ollama returned wrong intent for a file-creation command — retrying."
                    )
                    nudge = (
                        f"The user wants to CREATE a new file and write code into it. "
                        f"Return create_file JSON with target=filename, editor=app, content=full code.\n"
                        f"User command: {safe_text}"
                    )
                    retry_raw = await loop.run_in_executor(None, call_ollama, nudge)
                    if retry_raw:
                        if pii_context.has_pii():
                            retry_raw = engine.restore(retry_raw, pii_context)
                        retry_parsed = CommandParser.parse(retry_raw)
                        if retry_parsed.get("intent") == "create_file" and retry_parsed.get("content"):
                            logger.info("Retry succeeded — using create_file intent.")
                            return retry_parsed
                    # If retry also failed, fall through to local heuristic
                    local_cf = _detect_create_file_intent_locally(user_text)
                    if local_cf:
                        logger.info("Using local create_file heuristic as last resort.")
                        return local_cf

                # ── Sanity-check: Ollama returned open_app but the user said "write" ──
                # Re-invoke with an explicit nudge so content is actually generated.
                elif parsed.get("intent") == "open_app" and _WRITE_VERBS.search(user_text):
                    logger.warning(
                        "Ollama returned open_app for a write command — retrying with explicit prompt."
                    )
                    nudge = (
                        f"The user wants to write text inside an application. "
                        f"Generate the full text and return write_text JSON.\n"
                        f"User command: {safe_text}"
                    )
                    retry_raw = await loop.run_in_executor(None, call_ollama, nudge)
                    if retry_raw:
                        if pii_context.has_pii():
                            retry_raw = engine.restore(retry_raw, pii_context)
                        retry_parsed = CommandParser.parse(retry_raw)
                        if retry_parsed.get("intent") == "write_text" and retry_parsed.get("content"):
                            logger.info("Retry succeeded — using write_text intent.")
                            return retry_parsed
                    # If retry also failed, fall through to local heuristic
                    local = _detect_write_intent_locally(user_text)
                    if local:
                        logger.info("Using local write_text heuristic as last resort.")
                        return local

                # ── draw_shape sanity check ─────────────────────────────────
                # phi3 sometimes hallucinates the draw target (e.g. returns
                # "anime girl" when user said "cat").  Verify the parsed target
                # actually appears in the user's text; if not, fall back to
                # the locally extracted subject.
                if parsed.get("intent") == "draw_shape":
                    llm_target  = (parsed.get("target") or "").lower().strip()
                    user_lower  = user_text.lower()
                    target_words = llm_target.split()
                    target_in_text = any(
                        w in user_lower for w in target_words if len(w) > 2
                    )
                    if not target_in_text:
                        logger.warning(
                            f"draw_shape hallucination detected: LLM said '{llm_target}' "
                            f"but user said '{user_text}'. Extracting target locally."
                        )
                        local_draw = _detect_draw_intent_locally(user_text)
                        if local_draw:
                            logger.info(f"Corrected draw target to: '{local_draw['target']}'")
                            return local_draw

                # ── Phase 3: Store successful interaction ─────────────────────
                # Remember what the user asked and update preference learner.
                if self._memory_available and self.vector_memory:
                    try:
                        self.vector_memory.remember(
                            f"User said: {user_text}",
                            {
                                "type":   "conversation",
                                "intent": parsed.get("intent"),
                                "target": parsed.get("target"),
                            },
                        )
                        self.preference_learner.learn_from_command(
                            intent  = parsed.get("intent", ""),
                            target  = parsed.get("target", ""),
                            content = parsed.get("content", ""),
                        )
                    except Exception as e:
                        logger.debug(f"Memory store failed: {e}")

                return parsed

            logger.error("Ollama failed to return response. Falling back to offline parser.")
            fallback = _naive_fallback(user_text)

            # ── Phase 3: Store interaction in vector memory ───────────────────
            # Even on fallback we remember what the user asked.
            if self._memory_available and self.vector_memory:
                try:
                    self.vector_memory.remember(
                        f"User said: {user_text}",
                        {
                            "type":   "conversation",
                            "intent": fallback.get("intent"),
                            "target": fallback.get("target"),
                        },
                    )
                except Exception as e:
                    logger.debug(f"Memory store failed: {e}")

            return fallback

        except Exception as e:
            logger.error(f"Ollama failed with error: {e}")
            logger.error("Falling back to offline parser.")
            fallback = _naive_fallback(user_text)
            if fallback["intent"] == "error":
                fallback["message"] = f"API Error: {str(e)}"
            return fallback

